def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = ratio ** 3
        else:
            temp_sum = 0
            for j in range(1, 5):
                temp_sum += ((-1)**j) * (ratio**j) / j
            priorities[i] = -temp_sum
        if capacity < item * 1.5:
            priorities[i] *= 1.2
        else:
            priorities[i] *= 0.8
    max_priority = np.max(priorities)
    if max_priority > 0:
        priorities = priorities / max_priority
    else:
        priorities = np.zeros_like(priorities)
    return priorities
